            // Try using the switch at this node
            if (graph.has(node)) {
                for (const { to, weight } of graph.get(node)) {
                    const newCost = cost + 2 * weight;
                    if (dist[to] === -1 || newCost < dist[to]) {
                        dist[to] = newCost;
                        pq.enqueue([to, newCost, true]);
                    }
                }
            }
        }

        // Try moving normally without using the switch
        if (graph.has(node)) {
            for (const { to, weight } of graph.get(node)) {
                const newCost = cost + weight;
                if (dist[to] === -1 || newCost < dist[to]) {
                    dist[to] = newCost;
                    pq.enqueue([to, newCost, false]);
                }
            }
        }
    }

    return -1;
}

