from collections import defaultdict

def solve(n: int, edges: list[list[int]]) -> int:
    graph = defaultdict(list)
    for u, v, w in edges:
        graph[u].append((v, w))

    dist = [-1] * n
    dist[0] = 0

    pq = [(0, 0, False)]  # (node, cost, hasSwitchUsed)

    while pq:
        node, cost, hasSwitchUsed = heapq.heappop(pq)
        if node == n - 1:
            return cost
        if dist[node] < cost:
            continue

        if not hasSwitchUsed:
            # Try using the switch at this node
            for v, w in graph[node]:
                new_cost = cost + 2 * w
                if dist[v] == -1 or new_cost < dist[v]:
                    dist[v] = new_cost
                    heapq.heappush(pq, (v, new_cost, True))

        # Try moving normally without using the switch
        for v, w in graph[node]:
            new_cost = cost + w
            if dist[v] == -1 or new_cost < dist[v]:
                dist[v] = new_cost
                heapq.heappush(pq, (v, new_cost, False))

    return -1
